//ログイン画面
"use client";

import { useState } from "react";
export default function LoginPage() {
    //現在どの画面を見ているかを数字で管理する(0:選択、1:利用者、2:理学療法士)
    const [screenType, setScreenType] = useState(0);
    
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");

    //画面０：利用者・理学療法士選択画面
    if (screenType === 0) {
        return (
            <div style={{ padding: "40px", textAlign: "center" }}>
                <h2>ログインの種類を選んでください</h2>
                <div style={{ marginTop: "20px" }}>
                    <button 
                        onClick={() => setScreenType(1)}
                        style={{ padding: "20px", width: "200px", marginBottom: "10px", cursor: "pointer" }}>利用者としてログイン</button>
                    <br />
                    <button 
                        onClick={() => setScreenType(2)}
                        style={{ padding: "20px", width: "200px", cursor: "pointer" }}>理学療法士としてログイン</button>
                </div>
            </div>
        );
    }
    //画面１：利用者ログイン画面
    if(screenType === 1){
        return (
            <div style={{padding: "50px"}}>
                <h2>利用者ログイン</h2>
                <div style={{ marginTop: "20px" }}>
                    <p>メールアドレス</p>
                    <input type="email" value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    style={{ padding: "10px", width: "300px"}}/>
                </div>
                <div style={{ marginTop: "20px" }}>
                    <p>パスワード</p>
                    <input type="password" value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    style={{ padding: "10px", width: "300px"}}/>
                </div>
                <button 
                    style={{ marginTop: "20px", padding: "15px 30px" }}>ログイン</button>
            </div>
        );
    }

    //画面２：理学療法士ログイン画面
    if(screenType === 2){
        return (
            <div style={{padding: "50px"}}>
                <h2>理学療法士ログイン</h2>
                <div style={{ marginTop: "20px" }}>
                    <p>メールアドレス</p>
                    <input type="email" value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    style={{ padding: "10px", width: "300px"}}/>
                </div>
                <div style={{ marginTop: "20px" }}>
                    <p>パスワード</p>
                    <input type="password" value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    style={{ padding: "10px", width: "300px"}}/>
                </div>
                <button 
                    style={{ marginTop: "20px", padding: "15px 30px" }}>ログイン</button>
            </div>
        );
    }
    return null;
}   
